#include<stdio.h>
#include<string.h>
int main()
{
    int n,i,p=0,j=0;
    scanf("%d",&n);
    char s[n];
    scanf("%s",s);
    for(i=0;i<n;i++){
        if(s[i]=='S' && s[i+1]=='F'){
            p++;
        }
        else if(s[i]=='F' && s[i+1]=='S'){
            j++;
        }
    }
    if(p>j){
        printf("YES\n");
    }
    else{
        printf("NO\n");
    }
}

