fn solution(arg: String) -> bool {
  let mut sf = 0;
  let mut fs = 0;
  let mut prev_char;
  let mut c;
  let mut iter = arg.chars().peekable();
  prev_char = iter.next().unwrap(); 
  while iter.peek().is_some() {
    c = iter.next().unwrap();
    if prev_char == 'S' && c == 'F' {
      sf+=1;
    } else if prev_char == 'F' && c == 'S' {
      fs+=1;
    }
    prev_char =  c;
  }
  sf>fs
}

fn main() {
  assert_eq!(false,solution(String::from("FSSF")));
  assert_eq!(true,solution(String::from("SF")));
  assert_eq!(false,solution(String::from("FFFFFFFFFF")));
  assert_eq!(true,solution(String::from("SSFFSFFSFF")));


  let mut s = String::new();
  std::io::stdin().read_line(&mut s).unwrap();
  s = String::new();
  std::io::stdin().read_line(&mut s).unwrap();
  println!("{}", if solution(s) {"YES"} else {"NO"}); 
}
